import{_ as s,c as n,o as e,a8 as l}from"./chunks/framework.DMZhn_gK.js";const i="/assets/image-20260321200642145.B6Wjrlef.png",g=JSON.parse('{"title":"Velocity介绍","description":"Velocity介绍","frontmatter":{"title":"Velocity介绍","tags":["Java","Velocity"],"categories":["Java"],"date":"2026-3-21","description":"Velocity介绍","articleGPT":"Velocity介绍","references":[{"title":"docker","url":"https://github.com/imsyy/vitepress-theme-curve"}]},"headers":[],"relativePath":"java/Velocity.md","filePath":"java/Velocity.md","lastUpdated":1776154279000}'),t={name:"java/Velocity.md"};function p(c,a,r,o,d,u){return e(),n("div",null,[...a[0]||(a[0]=[l('<h2 id="介绍velocity" tabindex="-1">介绍Velocity <a class="header-anchor" href="#介绍velocity" aria-label="Permalink to &quot;介绍Velocity&quot;">​</a></h2><p>官网： <a href="https://velocity.apache.org/" target="_blank" rel="noreferrer">The Apache Velocity Project</a></p><p><img src="'+i+`" alt="image-20260321200642145" loading="lazy"></p><p><strong>Apache Velocity</strong> 是一个基于 Java 的开源模板引擎，由 Apache 软件基金会维护。它的核心理念是<strong>将业务逻辑（Java 代码）与表现层（页面设计）分离</strong>，遵循 MVC（模型 - 视图 - 控制器）设计模式中的“关注点分离”原则。</p><h3 id="_1-核心概念" tabindex="-1">1. 核心概念 <a class="header-anchor" href="#_1-核心概念" aria-label="Permalink to &quot;1. 核心概念&quot;">​</a></h3><p>Velocity 的工作流程主要涉及三个核心组件：</p><ul><li><strong>模板 (Template)</strong>：包含静态内容（如 HTML、XML、SQL 或纯文本）和动态指令（VTL 脚本）。模板文件通常以 <code>.vm</code> 为后缀。</li><li><strong>上下文 (Context)</strong>：一个数据容器（通常是 <code>VelocityContext</code> 对象），用于在 Java 应用程序和模板之间传递数据。开发者将业务数据放入 Context，模板从中读取并渲染。</li><li><strong>引擎 (VelocityEngine)</strong>：负责加载模板、合并上下文数据并生成最终输出的核心组件。</li></ul><h3 id="_2-velocity-模板语言-vtl" tabindex="-1">2. Velocity 模板语言 (VTL) <a class="header-anchor" href="#_2-velocity-模板语言-vtl" aria-label="Permalink to &quot;2. Velocity 模板语言 (VTL)&quot;">​</a></h3><p>Velocity 使用一种简单而强大的脚本语言，称为 <strong>VTL (Velocity Template Language)</strong>。它的设计目标是让网页设计师即使不懂 Java 编程，也能理解并修改动态页面。</p><p><strong>主要语法特性：</strong></p><ul><li><p><strong>变量引用</strong>：使用 <code>$</code> 或 <code>#</code> 符号。例如 <code>$variable</code> 或 <code>\${variable}</code>。</p></li><li><p><strong>注释</strong>:</p><ul><li>单行：<code>## 这是一个注释</code></li><li>多行：<code>#* 这是一个多行注释 *#</code></li></ul></li><li><p><strong>条件判断</strong>:</p><div class="language-velocity vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">velocity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#if ($condition)</span></span>
<span class="line"><span>    条件成立时显示的内容</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>    条件不成立时显示的内容</span></span>
<span class="line"><span>#end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></li><li><p><strong>循环语句</strong>:</p><div class="language-velocity vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">velocity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#foreach ($item in $list)</span></span>
<span class="line"><span>    序号[$foreach.index] 当前项：$item</span></span>
<span class="line"><span>#end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p><strong>宏定义 (Macro)</strong>:类似于函数，允许定义可重用的代码块。</p><div class="language-velocity vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">velocity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#macro (myMacro $arg)</span></span>
<span class="line"><span>    这里是宏的内容：$arg</span></span>
<span class="line"><span>#end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li></ul><h3 id="_3-简单示例" tabindex="-1">3. 简单示例 <a class="header-anchor" href="#_3-简单示例" aria-label="Permalink to &quot;3. 简单示例&quot;">​</a></h3><p>假设有一个 Java 应用传入一个用户列表 <code>users</code> 到 Context 中，模板 <code>user_list.vm</code> 可能如下：</p><div class="language-velocity vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">velocity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;html&gt;</span></span>
<span class="line"><span>&lt;body&gt;</span></span>
<span class="line"><span>  &lt;h1&gt;用户列表&lt;/h1&gt;</span></span>
<span class="line"><span>  &lt;ul&gt;</span></span>
<span class="line"><span>    #foreach ($user in $users)</span></span>
<span class="line"><span>      &lt;li&gt;$user.name - $user.email&lt;/li&gt;</span></span>
<span class="line"><span>    #end</span></span>
<span class="line"><span>  &lt;/ul&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span>
<span class="line"><span>&lt;/html&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>Velocity 会遍历 <code>$users</code> 集合，将每个用户的姓名和邮箱填充到 <code>&lt;li&gt;</code> 标签中，最终输出完整的 HTML 页面。</p><p>总的来说，Velocity 是一个经典且实用的 Java 模板引擎，特别适合需要快速生成文本内容且希望保持代码与视图清晰分离的项目。</p>`,16)])])}const m=s(t,[["render",p]]);export{g as __pageData,m as default};
